// Parse Znuny TicketGet response
// Format: { "Ticket": [{...vollstaendiges Ticket-Objekt...}] }
const input = $('📥 Input from Master').first().json;
const response = $input.first().json;
const ticket_id = input.ticket_id;

if (response.Error || !response.Ticket) {
  return [{
    json: {
      ticket_id, error: response.Error?.ErrorMessage || 'Ticket nicht gefunden',
      title: `Ticket ${ticket_id}`,
      wer: 'unknown', was: 'unknown', wan: new Date().toISOString(),
      priority: 'normal', status: 'unknown'
    }
  }];
}

const ticket = Array.isArray(response.Ticket) ? response.Ticket[0] : response.Ticket;

// DynamicFields: direkt als DynamicField_<Name> im Ticket-Objekt
// Znuny DynamicField-Namen: ZabbixWer, ZabbixWas, ZabbixWann, ZabbixReferenz, ZabbixKommentar
const wer  = ticket.DynamicField_ZabbixWer   || ticket.DynamicField_Wer  || 'unknown';
const was  = ticket.DynamicField_ZabbixWas   || ticket.DynamicField_Was  || ticket.Title || 'unknown';
const wan  = ticket.DynamicField_ZabbixWann  || ticket.DynamicField_Wan  || ticket.Created || new Date().toISOString();
const ref  = ticket.DynamicField_ZabbixReferenz || null;
const komm = ticket.DynamicField_ZabbixKommentar || null;

return [{
  json: {
    ticket_id: ticket.TicketID || ticket_id,
    ticket_number: ticket.TicketNumber || `TN-${ticket_id}`,
    title: ticket.Title || `Ticket ${ticket_id}`,
    wer, was, wan,
    zabbix_referenz: ref,
    zabbix_kommentar: komm,
    priority: ticket.Priority || 'normal',
    status: ticket.State || 'new',
    queue: ticket.Queue || 'unknown',
    owner: ticket.Owner || 'unknown',
    customer_user: ticket.CustomerUserID || 'unknown'
  }
}];
